     1→import { createServer } from 'node:http';
     2→import { resolve, isAbsolute } from 'node:path';
     3→import { watch } from 'node:fs';
     4→import { pruneWorktrees, findGitRepo } from './git/worktree.js';
     5→import { loadConfig } from './config/loader.js';
     6→import { configExists, runSetup } from './config/setup.js';
     7→import { StateStore } from './state/store.js';
     8→import { PipelineManager } from './pipeline/manager.js';
     9→import { createApp } from './web/server.js';
    10→import { attachWebSocket } from './web/ws-handler.js';
    11→
    12→const DEV_MODE = process.env.JIRANIMO_MODE === 'development';
    13→
    14→async function main() {
    15→  if (DEV_MODE) {
    16→    console.log('\n[DEV] Running in development mode\n');
    17→  }
    18→
    19→  // Load config — dev uses local file, prod uses global
    20→  let config;
    21→  if (DEV_MODE) {
    22→    const devConfigPath = resolve(process.cwd(), 'jiranimo.dev.config.json');
    23→    config = loadConfig({ configPath: devConfigPath });
    24→    // Resolve relative repoPath against cwd
    25→    if (!isAbsolute(config.repoPath)) {
    26→      config = { ...config, repoPath: resolve(process.cwd(), config.repoPath) };
    27→    }
    28→    // Set dev-local paths
    29→    config.statePath = config.statePath ?? resolve(process.cwd(), '.dev-state.json');
    30→    config.logsDir = config.logsDir ?? resolve(process.cwd(), '.dev-logs');
    31→  } else {
    32→    if (!configExists()) {
    33→      await runSetup();
    34→    }
    35→    config = loadConfig();
    36→  }
    37→
    38→  // Prune stale worktrees from previous crashes
    39→  const gitRepo = await findGitRepo(config.repoPath);
    40→  if (gitRepo) {
    41→    await pruneWorktrees(gitRepo);
    42→    console.log(`Pruned stale worktrees in ${gitRepo}`);
    43→  }
    44→
    45→  // State — dev uses local file, prod uses global default
    46→  const store = new StateStore(config.statePath ? { filePath: config.statePath } : undefined);
    47→  const pipeline = new PipelineManager(store, config);
    48→
    49→  const app = createApp(store, pipeline);
    50→  const server = createServer(app);
    51→  const wsHandler = attachWebSocket(server, pipeline);
    52→
    53→  // In dev mode, watch extension files and broadcast reload signal
    54→  if (DEV_MODE) {
    55→    startExtensionWatcher(wsHandler);
    56→  }
    57→
    58→  server.listen(config.web.port, config.web.host, () => {
    59→    console.log(`Jiranimo server running on http://${config.web.host}:${config.web.port}`);
    60→    console.log(`Dashboard: http://${config.web.host}:${config.web.port}`);
    61→    console.log(`Repo path: ${config.repoPath}`);
    62→
    63→    if (DEV_MODE) {
    64→      console.log(`\n[DEV] Config: ${resolve(process.cwd(), 'jiranimo.dev.config.json')}`);
    65→      console.log(`[DEV] State: ${config.statePath}`);
    66→      console.log(`[DEV] Logs: ${config.logsDir}`);
    67→      console.log(`[DEV] Extension auto-reload: enabled`);
    68→    } else {
    69→      const extensionPath = resolve(process.cwd(), '..', 'extension');
    70→      console.log(`\nTo install the Chrome extension:`);
    71→      console.log(`  1. Open chrome://extensions`);
    72→      console.log(`  2. Enable "Developer mode" (top right)`);
    73→      console.log(`  3. Click "Load unpacked"`);
    74→      console.log(`  4. Select: ${extensionPath}`);
    75→    }
    76→    console.log('');
    77→  });
    78→
    79→  let shuttingDown = false;
    80→  function shutdown() {
    81→    if (shuttingDown) return;
    82→    shuttingDown = true;
    83→    console.log('\nShutting down...');
    84→    store.flushSync();
    85→    store.destroy();
    86→    server.close(() => process.exit(0));
    87→    setTimeout(() => process.exit(0), 2000).unref();
    88→  }
    89→
    90→  process.on('SIGINT', shutdown);
    91→  process.on('SIGTERM', shutdown);
    92→}
    93→
    94→function startExtensionWatcher(wsHandler: ReturnType<typeof attachWebSocket>) {
    95→  const extensionDir = resolve(process.cwd(), '..', 'extension');
    96→  let debounceTimer: ReturnType<typeof setTimeout> | null = null;
    97→
    98→  try {
    99→    watch(extensionDir, { recursive: true }, (_event, filename) => {
   100→      if (!filename || filename.includes('node_modules')) return;
   101→      // Debounce — wait 500ms for batch changes
   102→      if (debounceTimer) clearTimeout(debounceTimer);
   103→      debounceTimer = setTimeout(() => {
   104→        console.log(`[DEV] Extension file changed: ${filename}`);
   105→        wsHandler.send({ type: 'extension-reload' });
   106→      }, 500);
   107→    });
   108→    console.log(`[DEV] Watching extension/ for changes`);
   109→  } catch (err) {
   110→    console.warn(`[DEV] Could not watch extension directory:`, err);
   111→  }
   112→}
   113→
   114→main();
   115→

