    10→export function createApp(store: StateStore, pipeline: PipelineManager) {
    11→  const app = express();
    12→
    13→  // CORS — allow requests from Jira and any origin (local tool, not public)
    14→  app.use((_req, res, next) => {
    15→    res.header('Access-Control-Allow-Origin', '*');
    16→    res.header('Access-Control-Allow-Methods', 'GET, POST, DELETE, OPTIONS');
    17→    res.header('Access-Control-Allow-Headers', 'Content-Type');
    18→    if (_req.method === 'OPTIONS') { res.sendStatus(204); return; }
    19→    next();
    20→  });
    21→
    22→  app.use(express.json());
    23→
    24→  // Request logging (after JSON parsing so body is available)
    25→  app.use((req, _res, next) => {
    26→    // Skip noisy polling requests
    27→    if (req.method === 'GET' && req.url === '/tasks') { next(); return; }
    28→    console.log(`${req.method} ${req.originalUrl}`);
    29→    if (req.method === 'POST' && req.body) {
    30→      console.log(`  Body: ${JSON.stringify(req.body).slice(0, 300)}`);
    31→    }
    32→    next();
    33→  });
    34→
    35→  // API routes
    36→  app.use('/api', createApiRouter(store, pipeline));
    37→
    38→  // Serve static dashboard
    39→  app.use(express.static(resolve(__dirname, 'public')));
    40→
    41→  return app;
    42→}
